#include <stdio.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int X,Y,Z; scanf("%d %d %d",&X,&Y,&Z);
        if(X + 2*Z >= Y) printf("YES\n");
        else printf("NO\n");
    }
    return 0;
}

